:root {
  --canvas: #EEFBF4;
  --surface: #FFFFFF;
  --primary: #14B8A6;
  --primary-strong: #0F766E;
  --primary-soft: #CCFBF1;
  --accent: #6366F1;
  --accent-soft: #E0E7FF;
  --ink: #0F172A;
  --mist: #64748B;
  --border: #E5E7EB;
  --coral: #FB7185;
  --coral-soft: #FFE4E6;
  --slate-50: #F8FAFC;
  --slate-100: #F1F5F9;

  --display: ui-rounded, "SF Pro Rounded", "Segoe UI Variable", "Nunito", system-ui, sans-serif;
  --body: system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", sans-serif;
  --mono: ui-monospace, "JetBrains Mono", Menlo, Consolas, monospace;

  --radius-sm: 12px;
  --radius: 16px;
  --radius-lg: 24px;

  --spring: cubic-bezier(0.2, 0.9, 0.3, 1.2);
  --ease-out: cubic-bezier(0.16, 1, 0.3, 1);

  --shadow-sm: 0 2px 8px rgba(15, 23, 42, 0.04);
  --shadow:    0 8px 24px rgba(15, 23, 42, 0.06);
  --shadow-lg: 0 18px 40px rgba(15, 23, 42, 0.08);
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  background: var(--canvas);
  color: var(--ink);
  font-family: var(--body);
  -webkit-font-smoothing: antialiased;
  -webkit-tap-highlight-color: transparent;
  overscroll-behavior: none;
}

body {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px;
}

button {
  font-family: inherit;
  cursor: pointer;
  border: none;
  background: none;
  color: inherit;
}

input, textarea {
  font-family: inherit;
  color: inherit;
}

@media (prefers-reduced-motion: reduce) {
  * {
    animation-duration: 0.01ms !important;
    transition-duration: 80ms !important;
  }
}

