export type Category = 'food' | 'household' | 'clothes' | 'tools' | 'other';
export type Freshness = 'today' | 'week' | 'month';

export type Post = {
  id: string;
  authorId: string;
  authorName: string;
  authorAvatarGradient: string;
  body: string;
  category: Category;
  freshness: Freshness;
  createdAt: number;
  expiresAt: number;
  distanceMeters: number;
  photoColor: string;
  state: 'live' | 'gone';
  mine: boolean;
};

export type SwipeDecision = 'yes' | 'no';

export type Swipe = {
  postId: string;
  decision: SwipeDecision;
  at: number;
};

export type Message = {
  from: 'me' | 'them';
  text: string;
  at: number;
};

export type Match = {
  id: string;
  postId: string;
  postBody: string;
  postCategory: Category;
  partnerId: string;
  partnerName: string;
  partnerAvatarGradient: string;
  matchedAt: number;
  distanceMeters: number;
  roughLocation: string;
  messages: Message[];
  unread: boolean;
};

