  food: 'Food',
  household: 'Household',
  clothes: 'Clothes',
  tools: 'Tools',
  other: 'Other',
};

export const FRESHNESS_LABEL: Record<Freshness, string> = {
  today: 'Today only',
  week: 'This week',
  month: 'This month',
};

