input.content:
export function uid(prefix = 'id'): string {
  return `${prefix}_${Math.random().toString(36).slice(2, 9)}`;
}

export function formatDistance(meters: number): string {
  if (meters < 1000) return `${meters}m`;
  return `${(meters / 1000).toFixed(1)}km`;
}

export function formatTimeAgo(ts: number): string {
  const diff = Date.now() - ts;
  const m = Math.floor(diff / 60000);
  if (m < 1) return 'just now';
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  const d = Math.floor(h / 24);
  return `${d}d ago`;
}

export function formatClock(ts: number): string {
  const d = new Date(ts);
  const hh = d.getHours();
  const mm = d.getMinutes().toString().padStart(2, '0');
  return `${hh}:${mm}`;
}

export function freshnessMs(f: 'today' | 'week' | 'month'): number {
  const h = 60 * 60 * 1000;
  if (f === 'today') return 12 * h;
  if (f === 'week') return 7 * 24 * h;
  return 30 * 24 * h;
}

export function freshnessChip(f: 'today' | 'week' | 'month'): string {
  if (f === 'today') return 'Until tonight';
  if (f === 'week') return 'This week';
  return 'This month';
}

