input.content:
import type { Match, Message, Post, Swipe, SwipeDecision } from './types';
import { seedPosts, ME } from './seed';
import { freshnessMs, uid } from './util';

type Tab = 'feed' | 'matches' | 'post' | 'you';

const STORAGE_KEY = 'passit_state_v1';

type Persisted = {
  posts: Post[];
  swipes: Swipe[];
  matches: Match[];
};

function loadPersisted(): Persisted | null {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as Persisted;
    if (!Array.isArray(parsed.posts)) return null;
    return parsed;
  } catch {
    return null;
  }
}

const initial = loadPersisted();

export const session = $state({
  tab: 'feed' as Tab,
  me: ME,
  openMatchId: null as string | null,
  overlayMatchId: null as string | null,
});

export const postsStore = $state({
  items: (initial?.posts ?? seedPosts()) as Post[],
});

export const swipesStore = $state({
  items: (initial?.swipes ?? []) as Swipe[],
});

export const matchesStore = $state({
  items: (initial?.matches ?? []) as Match[],
});

let savePending = false;
function scheduleSave() {
  if (savePending) return;
  savePending = true;
  queueMicrotask(() => {
    savePending = false;
    try {
      const snapshot: Persisted = {
        posts: postsStore.items,
        swipes: swipesStore.items,
        matches: matchesStore.items,
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(snapshot));
    } catch {
      // ignore
    }
  });
}

$effect.root(() => {
  $effect(() => {
    // touch the reactive arrays to re-run on change
    postsStore.items.length;
    swipesStore.items.length;
    matchesStore.items.length;
    scheduleSave();
  });
});

export function setTab(t: Tab) {
  session.tab = t;
  if (t !== 'matches') session.openMatchId = null;
}

export function openMatch(id: string) {
  session.openMatchId = id;
  const m = matchesStore.items.find((x) => x.id === id);
  if (m) m.unread = false;
  session.tab = 'matches';
}

export function closeMatch() {
  session.openMatchId = null;
}

export function dismissOverlay() {
  const id = session.overlayMatchId;
  session.overlayMatchId = null;
  if (id) openMatch(id);
}

export function addPost(body: string, category: Post['category'], freshness: Post['freshness']) {
  const now = Date.now();
  const post: Post = {
    id: uid('p'),
    authorId: session.me.id,
    authorName: session.me.name,
    authorAvatarGradient: session.me.avatarGradient,
    body,
    category,
    freshness,
    createdAt: now,
    expiresAt: now + freshnessMs(freshness),
    distanceMeters: 0,
    photoColor: 'linear-gradient(135deg, #CCFBF1, #5EEAD4 55%, #14B8A6)',
    state: 'live',
    mine: true,
  };
  postsStore.items = [post, ...postsStore.items];
  scheduleSave();
}

export function markGone(postId: string) {
  const p = postsStore.items.find((x) => x.id === postId);
  if (p) p.state = 'gone';
  scheduleSave();
}

export function recordSwipe(postId: string, decision: SwipeDecision) {
  swipesStore.items = [...swipesStore.items, { postId, decision, at: Date.now() }];
  if (decision === 'yes') maybeMatch(postId);
  scheduleSave();
}

function maybeMatch(postId: string) {
  const post = postsStore.items.find((p) => p.id === postId);
  if (!post || post.mine) return;
  if (matchesStore.items.some((m) => m.postId === postId)) return;

  const delay = 800 + Math.random() * 1800;
  const accept = Math.random() < 0.7;
  if (!accept) return;

  setTimeout(() => {
    const opener = openerFor(post.body);
    const match: Match = {
      id: uid('m'),
      postId: post.id,
      postBody: post.body,
      postCategory: post.category,
      partnerId: post.authorId,
      partnerName: post.authorName,
      partnerAvatarGradient: post.authorAvatarGradient,
      matchedAt: Date.now(),
      distanceMeters: post.distanceMeters,
      roughLocation: `${roughArea(post.distanceMeters)} area`,
      messages: [
        { from: 'them', text: opener, at: Date.now() },
      ],
      unread: true,
    };
    matchesStore.items = [match, ...matchesStore.items];
    session.overlayMatchId = match.id;
    scheduleSave();
  }, delay);
}

function roughArea(meters: number): string {
  if (meters < 400) return 'Green Street';
  if (meters < 800) return 'Mill Lane';
  if (meters < 1500) return 'Park End';
  return 'Across the park';
}

function openerFor(body: string): string {
  const lower = body.toLowerCase();
  if (lower.includes('tomato')) return 'Hi! Still available if you want them.';
  if (lower.includes('bread') || lower.includes('sourdough')) return 'Hey! Still warm from this morning. Yours if you like.';
  if (lower.includes('lamp')) return 'Hi! Still looking for a home. When works for you?';
  if (lower.includes('shirt')) return 'Hey! Size M, freshly washed. Want to try it?';
  if (lower.includes('drill')) return 'Hi! It comes with two batteries. When would you swing by?';
  if (lower.includes('basil') || lower.includes('plant')) return 'Hi! They need a sunnier spot than mine. Want all three?';
  if (lower.includes('book')) return 'Hey! Pick a couple or take the lot, up to you.';
  if (lower.includes('mug')) return 'Hi! Happy to pass them on. Cafe nearby if you want to meet?';
  return 'Hi! Happy to pass it on. When works for you?';
}

export function sendMessage(matchId: string, text: string) {
  const m = matchesStore.items.find((x) => x.id === matchId);
  if (!m) return;
  m.messages = [...m.messages, { from: 'me', text, at: Date.now() }];
  scheduleSave();

  setTimeout(() => {
    const reply = autoReply(text);
    if (!reply) return;
    const mm = matchesStore.items.find((x) => x.id === matchId);
    if (!mm) return;
    mm.messages = [...mm.messages, { from: 'them', text: reply, at: Date.now() }];
    if (session.openMatchId !== matchId) mm.unread = true;
    scheduleSave();
  }, 1400 + Math.random() * 1200);
}

function autoReply(text: string): string | null {
  const lower = text.toLowerCase();
  if (/\b\d{1,2}(:\d{2})?\s?(am|pm|today|tonight|tomorrow)?\b/.test(lower)) {
    return "Works for me. I'll send the exact door number when you're close.";
  }
  if (lower.includes('thanks') || lower.includes('thank you')) {
    return 'No worries, glad it finds a home.';
  }
  if (lower.includes('?')) {
    return 'Whatever suits you, I am around most of the evening.';
  }
  return 'Sounds good!';
}

export function remainingFeed(): Post[] {
  const swipedIds = new Set(swipesStore.items.map((s) => s.postId));
  const now = Date.now();
  return postsStore.items.filter(
    (p) => !p.mine && p.state === 'live' && p.expiresAt > now && !swipedIds.has(p.id),
  );
}

export function myLivePosts(): Post[] {
  const now = Date.now();
  return postsStore.items.filter((p) => p.mine && p.state === 'live' && p.expiresAt > now);
}

export function myPassedOnCount(): number {
  return postsStore.items.filter((p) => p.mine && p.state === 'gone').length;
}

export function resetAll() {
  localStorage.removeItem(STORAGE_KEY);
  postsStore.items = seedPosts();
  swipesStore.items = [];
  matchesStore.items = [];
  session.tab = 'feed';
  session.openMatchId = null;
  session.overlayMatchId = null;
}

