1	<script lang="ts">
2	  // Subtle top-right indicator that reflects what Claude Code is doing in
3	  // the background, fed by scripts/status-bridge.mjs over SSE. If the
4	  // bridge isn't running (e.g. the compiled single-file HTML a student
5	  // opens), the component stays invisible - no broken UI in the wild.
6	
7	  import { STAGE_WIDTH, STAGE_HEIGHT } from '$lib/constants';
8	
9	  type Status = 'ready' | 'working' | 'input-needed';
10	
11	  const BRIDGE_URL = 'http://127.0.0.1:7321/events';
12	
13	  let connected = $state(false);
14	  let status = $state<Status>('ready');
15	  let source: EventSource | null = null;
16	  let everConnected = false;
17	  let givenUp = false;
18	
19	  // Scale the indicator with the rest of the stage, matching the nav bar.
20	  let winW = $state(window.innerWidth);
21	  let winH = $state(window.innerHeight);
22	  const fitScale = $derived(
23	    Math.min(winW / STAGE_WIDTH, winH / STAGE_HEIGHT),
24	  );
25	
26	  function onResize() {
27	    winW = window.innerWidth;
28	    winH = window.innerHeight;
29	  }
30	
31	  const LABELS: Record<Status, string> = {
32	    'ready': 'ready',
33	    'working': 'working',
34	    'input-needed': 'input needed'
35	  };
36	
37	  // Sprinkler burst: a rotating emitter drops particles over ~1.4s. Each
38	  // particle's `angle` and `delay` advance together so they appear as a
39	  // single nozzle sweeping ~2 full rotations. Sizes, distances and
40	  // lifetimes are varied with small deterministic jitter for organic feel.
41	  const PARTICLES = (() => {
42	    const count = 60;
43	    const totalSpin = 1080;  // deg of nozzle rotation over the emit window (3 revs)
44	    const emitMs = 1400;
45	    return Array.from({ length: count }, (_, i) => {
46	      const t = i / (count - 1);
47	      const r = (i * 7919) % 1000 / 1000;
48	      const size = r < 0.55 ? 3 : r < 0.85 ? 5 : 7;
49	      const jitter = ((i * 47) % 24) - 12;
50	      return {
51	        angle: totalSpin * t + jitter,
52	        size,
53	        dist: 38 + ((i * 13) % 58),
54	        delay: Math.round(emitMs * t),
55	        life: 720 + ((i * 29) % 360)
56	      };
57	    });
58	  })();
59	
60	  // Trigger the ready-burst whenever status transitions INTO 'ready' from
61	  // anywhere else. `prevStatus` is a plain let (not $state) so the effect
62	  // only re-runs when `status` changes, avoiding a reactivity loop.
63	  let prevStatus: Status = 'ready';
64	  let burstId = $state(0);
65	
66	  $effect(() => {
67	    if (status === 'ready' && prevStatus !== 'ready') {
68	      burstId += 1;
69	    }
70	    prevStatus = status;
71	  });
72	
73	  // Dev hotkey: press P to replay the ready-burst for visual inspection.
74	  function handleKeydown(e: KeyboardEvent) {
75	    if (e.key !== 'p' && e.key !== 'P') return;
76	    if (e.metaKey || e.ctrlKey || e.altKey) return;
77	    const t = e.target as HTMLElement | null;
78	    if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.isContentEditable)) return;
79	    burstId += 1;
80	  }
81	
82	  function connect() {
83	    try {
84	      source = new EventSource(BRIDGE_URL);
85	    } catch {
86	      return;
87	    }
88	    source.onopen = () => {
89	      connected = true;
90	      everConnected = true;
91	    };
92	    source.onmessage = (e) => {
93	      try {
94	        const msg = JSON.parse(e.data);
95	        if (msg && typeof msg.status === 'string') {
96	          if (msg.status === 'ready' || msg.status === 'working' || msg.status === 'input-needed') {
97	            status = msg.status;
98	            connected = true;
99	            everConnected = true;
100	          }
101	        }
102	      } catch { /* ignore malformed */ }
103	    };
104	    // Hide on error. If we never reached the bridge at all, give up after
105	    // the first failure so the compiled single-file build doesn't spam
106	    // connection attempts on a student's machine. Once we've connected at
107	    // least once, EventSource's built-in reconnect is fine.
108	    source.onerror = () => {
109	      connected = false;
110	      if (!everConnected && !givenUp) {
111	        givenUp = true;
112	        source?.close();
113	        source = null;
114	      }
115	    };
116	  }
117	
118	  $effect(() => {
119	    connect();
120	    return () => {
121	      source?.close();
122	      source = null;
123	    };
124	  });
125	</script>
