141	            <stop offset="0%" class="mark-stop-from" />
142	            <stop offset="100%" class="mark-stop-to" />
143	          </linearGradient>
144	        </defs>
145	        <circle cx="12" cy="12" r="11" fill="url(#ai-mark-grad)" />
146	        <path
147	          d="M12 5 L13.2 10.8 L19 12 L13.2 13.2 L12 19 L10.8 13.2 L5 12 L10.8 10.8 Z"
148	          fill="#fff"
149	        />
150	      </svg>
151	      {#key burstId}
152	        {#if burstId > 0}
153	          <span class="burst">
154	            {#each PARTICLES as p}
155	              <span
156	                class="particle"
157	                style="--angle: {p.angle}deg; --dist: {p.dist}px; --size: {p.size}px; --delay: {p.delay}ms; --life: {p.life}ms;"
158	              ></span>
159	            {/each}
160	          </span>
161	        {/if}
162	      {/key}
163	    </span>
164	    <span class="label">{LABELS[status]}</span>
165	  </div>
166	{/if}
167	
