180	    backdrop-filter: blur(10px);
181	    -webkit-backdrop-filter: blur(10px);
182	    font-family: 'JetBrains Mono', ui-monospace, Menlo, monospace;
183	    font-size: 13px;
184	    letter-spacing: 0.14em;
185	    text-transform: uppercase;
186	    color: rgba(255, 255, 255, 0.62);
187	    z-index: 1000;
188	    pointer-events: none;
189	    user-select: none;
190	    transition: background 0.3s ease, border-color 0.3s ease, color 0.3s ease;
191	    animation: si-fade-in 0.4s ease-out;
192	  }
193	
194	  .ai-mark {
195	    position: relative;
196	    display: inline-flex;
197	    align-items: center;
198	    justify-content: center;
199	    width: 48px;
200	    height: 48px;
201	    filter: drop-shadow(0 0 8px var(--mark-glow, rgba(16, 185, 129, 0.5)));
202	    transition: filter 0.3s ease;
203	  }
204	
205	  .mark-svg {
206	    position: relative;
207	    z-index: 1;
208	    width: 40px;
209	    height: 40px;
210	  }
211	
212	  /* Rotating trail: a conic-gradient ring masked to the outer edge of the
213	     AI disc, rotating clockwise. Head (bright) + fading tail gives the
214	     illusion of a dot sweeping around the circular path. Only visible
215	     while working. */
216	  .trail {
217	    position: absolute;
218	    inset: 0;
219	    border-radius: 50%;
220	    background: conic-gradient(
221	      from 0deg,
