241	  }
242	  :global(.mark-stop-to) {
243	    stop-color: var(--mark-to, #059669);
244	    transition: stop-color 0.3s ease;
245	  }
246	
247	  /* Ready: calm green, no motion. */
248	  .status-indicator[data-status='ready'] {
249	    --mark-from: #34d399;
250	    --mark-to: #059669;
251	    --mark-glow: rgba(16, 185, 129, 0.5);
252	  }
253	
254	  /* Working: amber, subtle clockwise dot+trail sweeping around the disc. */
255	  .status-indicator[data-status='working'] {
256	    --mark-from: #fbbf24;
257	    --mark-to: #d97706;
258	    --mark-glow: rgba(245, 158, 11, 0.6);
259	    color: rgba(255, 255, 255, 0.78);
260	  }
261	  .status-indicator[data-status='working'] .trail {
262	    opacity: 1;
263	    animation: trail-spin 2.2s linear infinite;
264	  }
265	
266	  /* Input needed: pink, urgent pulse + border accent so it catches the eye. */
267	  .status-indicator[data-status='input-needed'] {
268	    --mark-from: #f472b6;
269	    --mark-to: #db2777;
270	    --mark-glow: rgba(236, 72, 153, 0.75);
271	    color: #fff;
272	    border-color: rgba(236, 72, 153, 0.55);
