274	  }
275	  .status-indicator[data-status='input-needed'] .ai-mark {
276	    animation: si-pulse-fast 0.9s ease-in-out infinite;
277	  }
278	
279	  @keyframes trail-spin {
280	    from { transform: rotate(0deg); }
