2	  import { onMount, onDestroy, tick } from 'svelte';
3	  import { registerStage, unregisterStage } from '$lib/stage/stage-registry';
4	  import { careAuditStage } from './stage.svelte';
5	  import { AUDIT_DATA, type AuditSession, type AuditEvent } from './data';
6	
7	  let { segmentId = 'care-audit' }: { segmentId?: string } = $props();
8	
9	  onMount(() => registerStage(segmentId, careAuditStage));
10	  onDestroy(() => unregisterStage(segmentId));
11	
12	  // === Timeline state ================================================
13	  //
14	  // The viewport is a time-range [tMin, tMax] in epoch ms. Default = the
15	  // full span of the recorded sessions plus a small padding at each end.
16	
17	  const FIRST = AUDIT_DATA.firstMs;
18	  const LAST = AUDIT_DATA.lastMs;
19	  const FULL_SPAN = LAST - FIRST;
20	  const PAD = FULL_SPAN * 0.02;
21	  const T_MIN_INIT = FIRST - PAD;
22	  const T_MAX_INIT = LAST + PAD;
23	
24	  let tMin = $state(T_MIN_INIT);
25	  let tMax = $state(T_MAX_INIT);
26	
27	  // Canvas dimensions tracked via ResizeObserver.
28	  let canvasEl: HTMLCanvasElement | null = $state(null);
29	  let wrapperEl: HTMLDivElement | null = $state(null);
30	  let canvasW = $state(0);
31	  let canvasH = $state(0);
32	  let dpr = $state(1);
33	
34	  // Hover + selection.
35	  let hoverId = $state<string | null>(null);
36	  let selectedId = $state<string | null>(null);
37	
38	  // Pointer drag state (for panning).
39	  let isPanning = $state(false);
40	  let panStartX = 0;
41	  let panStartT = 0;
42	  let dragMoved = false;
43	
44	  const selectedSession = $derived(
45	    selectedId ? AUDIT_DATA.sessions.find((s) => s.id === selectedId) ?? null : null,
46	  );
47	
48	  // === Canvas setup / resize =========================================
49	
50	  let ro: ResizeObserver | null = null;
51	
52	  $effect(() => {
53	    if (!wrapperEl) return;
54	    dpr = window.devicePixelRatio || 1;
55	    ro = new ResizeObserver((entries) => {
56	      for (const entry of entries) {
57	        const { width, height } = entry.contentRect;
58	        canvasW = Math.max(1, Math.round(width));
59	        canvasH = Math.max(1, Math.round(height));
60	        resizeCanvas();
61	      }
62	    });
63	    ro.observe(wrapperEl);
64	    return () => ro?.disconnect();
65	  });
66	
67	  function resizeCanvas() {
68	    if (!canvasEl) return;
69	    // Backing buffer sized in device pixels for crisp output. The canvas's
70	    // CSS size is driven by the stylesheet (width: 100% of wrapper), so
71	    // the element shrinks happily when the layout splits in half - no
72	    // inline width to fight the grid.
73	    canvasEl.width = Math.round(canvasW * dpr);
74	    canvasEl.height = Math.round(canvasH * dpr);
75	    draw();
76	  }
77	
78	  // === Time <-> screen conversion ======================================
79	
80	  function tToX(t: number): number {
81	    return ((t - tMin) / (tMax - tMin)) * canvasW;
82	  }
83	  function xToT(x: number): number {
84	    return tMin + (x / canvasW) * (tMax - tMin);
85	  }
86	
87	  // === Zoom (mouse wheel, centred on cursor) ==========================
88	
89	  // The whole segment sits inside the camera's CSS transform, so a canvas
90	  // that is logically 1920px wide can appear at, say, 1366px on screen.
91	  // getBoundingClientRect() reports the *visual* (post-transform) size,
92	  // so we have to rescale clientX into the canvas's logical pixel space
93	  // before feeding it to anything that uses `canvasW`.
94	  function pointerToLogicalX(ev: PointerEvent | WheelEvent): number {
95	    if (!canvasEl) return 0;
96	    const rect = canvasEl.getBoundingClientRect();
97	    if (rect.width === 0) return 0;
98	    return ((ev.clientX - rect.left) / rect.width) * canvasW;
99	  }
100	
101	  function onWheel(ev: WheelEvent) {
102	    ev.preventDefault();
103	    if (!canvasEl) return;
104	    const x = pointerToLogicalX(ev);
105	    // Normalise across browsers/trackpads.
106	    const k = Math.exp(ev.deltaY * 0.0015);
107	    zoomAt(x, k);
108	  }
109	
110	  function zoomAt(x: number, factor: number) {
111	    const tAtCursor = xToT(x);
112	    const newSpan = Math.max(
113	      30_000, // min 30 seconds visible
114	      Math.min(FULL_SPAN * 2, (tMax - tMin) * factor),
115	    );
116	    const left = tAtCursor - (x / canvasW) * newSpan;
117	    tMin = left;
118	    tMax = left + newSpan;
119	    clampViewport();
120	    draw();
121	  }
122	
123	  function clampViewport() {
124	    const span = tMax - tMin;
125	    if (span > FULL_SPAN * 2) {
126	      const c = (tMin + tMax) / 2;
127	      tMin = c - FULL_SPAN;
128	      tMax = c + FULL_SPAN;
129	    }
130	    // Soft pan limits - allow small overshoot at each edge for breathing.
131	    const maxOver = span * 0.3;
132	    if (tMin < FIRST - maxOver) {
133	      tMin = FIRST - maxOver;
134	      tMax = tMin + span;
135	    }
136	    if (tMax > LAST + maxOver) {
137	      tMax = LAST + maxOver;
138	      tMin = tMax - span;
139	    }
140	  }
141	
142	  // === Pan (drag) =====================================================
143	
144	  function onPointerDown(ev: PointerEvent) {
145	    if (!canvasEl) return;
146	    try {
147	      (ev.currentTarget as HTMLElement).setPointerCapture(ev.pointerId);
148	    } catch {
149	      // Some pointer types may refuse capture; non-fatal.
150	    }
151	    isPanning = true;
152	    dragMoved = false;
153	    panStartX = pointerToLogicalX(ev);
154	    panStartT = tMin;
155	  }
156	
157	  function onPointerMove(ev: PointerEvent) {
158	    if (!canvasEl) return;
159	    const x = pointerToLogicalX(ev);
160	
161	    if (isPanning) {
162	      const dx = x - panStartX;
163	      const dt = (dx / canvasW) * (tMax - tMin);
164	      const span = tMax - tMin;
165	      tMin = panStartT - dt;
166	      tMax = tMin + span;
167	      clampViewport();
168	      // Threshold in logical px; a little generous so jittery clicks still
169	      // register as clicks rather than micro-pans.
170	      if (Math.abs(dx) > 5) dragMoved = true;
171	      draw();
172	    } else {
173	      const sess = sessionAt(x);
174	      if (hoverId !== (sess?.id ?? null)) {
175	        hoverId = sess?.id ?? null;
176	        draw();
177	      }
178	    }
179	  }
180	
181	  function onPointerUp(ev: PointerEvent) {
182	    if (!canvasEl) return;
183	    try {
184	      (ev.currentTarget as HTMLElement).releasePointerCapture(ev.pointerId);
185	    } catch {
186	      // ignore
187	    }
188	    const wasPanning = isPanning;
189	    isPanning = false;
190	    if (wasPanning && !dragMoved) {
191	      // Treat as click.
192	      const x = pointerToLogicalX(ev);
193	      const sess = sessionAt(x);
194	      if (sess) {
195	        selectedId = selectedId === sess.id ? null : sess.id;
196	      }
197	    }
198	  }
199	
200	  function onPointerLeave() {
201	    if (hoverId !== null) {
202	      hoverId = null;
