207	  // === Hit testing ==================================================
208	
209	  // Session blocks occupy the full canvas height; we hit-test in time
210	  // space only. x is in the canvas's logical pixel space.
211	  function sessionAt(x: number): AuditSession | null {
212	    const t = xToT(x);
213	    // Small forgiveness on the edges - makes clicking narrow blocks viable.
214	    const slackMs = ((tMax - tMin) / canvasW) * 4;
