257	    tool: {
258	      fill: 'rgba(96, 165, 250, 0.7)',
259	      stroke: 'rgba(96, 165, 250, 0.95)',
260	      label: 'tool',
261	    },
262	  };
263	
264	  function fmtDate(t: number): string {
265	    const d = new Date(t);
266	    return d.toLocaleDateString('en-GB', { month: 'short', day: 'numeric' });
267	  }
268	
269	  function fmtDateTime(t: number): string {
270	    const d = new Date(t);
271	    return (
272	      d.toLocaleDateString('en-GB', { month: 'short', day: 'numeric' }) +
273	      ' · ' +
274	      d.toLocaleTimeString('en-GB', {
275	        hour: '2-digit',
276	        minute: '2-digit',
277	      })
278	    );
279	  }
280	
281	  function fmtDuration(ms: number): string {
282	    const s = Math.round(ms / 1000);
283	    if (s < 60) return `${s}s`;
284	    const m = Math.round(s / 60);
285	    if (m < 60) return `${m}m`;
286	    const h = Math.floor(m / 60);
287	    const rest = m % 60;
288	    return `${h}h ${rest}m`;
289	  }
290	
291	  // Finer-grained formatter for event-level durations that can be very
292	  // short (tool calls often complete in milliseconds).
293	  function fmtShortDur(ms: number): string {
294	    if (ms < 1000) return `${Math.round(ms)}ms`;
295	    if (ms < 10_000) return `${(ms / 1000).toFixed(1)}s`;
296	    if (ms < 60_000) return `${Math.round(ms / 1000)}s`;
297	    const m = Math.floor(ms / 60_000);
298	    const s = Math.round((ms % 60_000) / 1000);
299	    if (m < 60) return s ? `${m}m ${s}s` : `${m}m`;
300	    const h = Math.floor(m / 60);
301	    const mm = m % 60;
302	    return `${h}h ${mm}m`;
303	  }
304	
305	  // Detail-fade thresholds, in ms of *visible timespan*. Details are
306	  // invisible at wide zoom, fully visible at tight zoom, linearly
307	  // interpolated in between. Zooming past the in-threshold is no more
308	  // visible, zooming out past the out-threshold fully hides the strip.
309	  const DETAIL_FADE_OUT_SPAN_MS = 12 * 60 * 60 * 1000; // 12h visible
310	  const DETAIL_FADE_IN_SPAN_MS = 3 * 60 * 60 * 1000; //  3h visible
311	
312	  // Computed per-draw and read by drawSession / drawEventMarkers below.
313	  let detailOpacity = 0;
314	
315	  function draw() {
316	    if (!canvasEl) return;
317	    const ctx = canvasEl.getContext('2d');
318	    if (!ctx) return;
319	    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
320	
321	    const w = canvasW;
322	    const h = canvasH;
323	    ctx.clearRect(0, 0, w, h);
324	
325	    // Background grid: faint vertical date gridlines.
326	    const span = tMax - tMin;
327	    const gridInterval = chooseGridInterval(span, w);
328	    drawGrid(ctx, gridInterval, w, h);
329	
330	    // Zoom-based detail opacity. Shared by every session block this
331	    // frame so they all reveal or dim together as the user scrolls.
332	    if (span >= DETAIL_FADE_OUT_SPAN_MS) {
333	      detailOpacity = 0;
334	    } else if (span <= DETAIL_FADE_IN_SPAN_MS) {
335	      detailOpacity = 1;
336	    } else {
337	      detailOpacity =
338	        (DETAIL_FADE_OUT_SPAN_MS - span) /
339	        (DETAIL_FADE_OUT_SPAN_MS - DETAIL_FADE_IN_SPAN_MS);
340	    }
341	    // Ease the linear factor for a softer transition than a pure ramp.
342	    detailOpacity = detailOpacity * detailOpacity * (3 - 2 * detailOpacity);
343	
344	    // Session blocks.
345	    const blockTop = BLOCK_PAD_Y;
346	    const blockBottom = h - AXIS_H - BLOCK_PAD_Y;
347	    const blockHeight = blockBottom - blockTop;
348	    const pxPerMs = w / span;
349	
350	    for (const s of AUDIT_DATA.sessions) {
351	      const x = tToX(s.startMs);
352	      const width = s.durationMs * pxPerMs;
353	      if (x + width < 0 || x > w) continue;
354	      drawSession(
355	        ctx,
356	        s,
357	        x,
358	        blockTop,
359	        Math.max(2, width),
360	        blockHeight,
361	        pxPerMs,
362	      );
363	    }
364	
365	    // Time axis at the bottom.
366	    drawAxis(ctx, gridInterval, w, h);
367	  }
368	
369	  function chooseGridInterval(spanMs: number, wPx: number): number {
370	    // Aim for ~10 gridlines across.
371	    const targetCount = 10;
372	    const rough = spanMs / targetCount;
373	    const candidates = [
374	      60_000, // 1min
375	      5 * 60_000,
376	      15 * 60_000,
377	      30 * 60_000,
378	      60 * 60_000, // 1h
379	      3 * 60 * 60_000,
380	      6 * 60 * 60_000,
381	      12 * 60 * 60_000,
382	      24 * 60 * 60_000, // 1d
383	      3 * 24 * 60 * 60_000,
384	      7 * 24 * 60 * 60_000,
385	      14 * 24 * 60 * 60_000,
386	      30 * 24 * 60 * 60_000,
387	    ];
388	    for (const c of candidates) if (c >= rough) return c;
389	    return candidates[candidates.length - 1];
390	  }
391	
392	  function drawGrid(
393	    ctx: CanvasRenderingContext2D,
394	    interval: number,
395	    w: number,
396	    h: number,
397	  ) {
398	    const start = Math.floor(tMin / interval) * interval;
399	    ctx.strokeStyle = 'rgba(255, 255, 255, 0.04)';
400	    ctx.lineWidth = 1;
401	    ctx.beginPath();
402	    for (let t = start; t <= tMax; t += interval) {
403	      const x = tToX(t);
404	      if (x < 0 || x > w) continue;
405	      ctx.moveTo(x, 0);
406	      ctx.lineTo(x, h - AXIS_H);
407	    }
408	    ctx.stroke();
409	  }
410	
411	  function drawAxis(
412	    ctx: CanvasRenderingContext2D,
413	    interval: number,
414	    w: number,
415	    h: number,
416	  ) {
417	    const axisY = h - AXIS_H;
418	    // Axis baseline
419	    ctx.strokeStyle = 'rgba(255, 255, 255, 0.12)';
420	    ctx.beginPath();
421	    ctx.moveTo(0, axisY);
422	    ctx.lineTo(w, axisY);
423	    ctx.stroke();
424	
425	    const start = Math.floor(tMin / interval) * interval;
426	    ctx.fillStyle = 'rgba(242, 242, 248, 0.55)';
427	    ctx.font = '13px "JetBrains Mono", ui-monospace, monospace';
428	    ctx.textBaseline = 'top';
429	    ctx.textAlign = 'left';
430	
431	    const dayMs = 24 * 60 * 60_000;
432	    const showTime = interval < dayMs;
433	
434	    for (let t = start; t <= tMax; t += interval) {
435	      const x = tToX(t);
436	      if (x < 0 || x > w) continue;
437	      ctx.strokeStyle = 'rgba(255, 255, 255, 0.2)';
438	      ctx.beginPath();
439	      ctx.moveTo(x, axisY);
440	      ctx.lineTo(x, axisY + 6);
441	      ctx.stroke();
442	      const label = showTime ? fmtDateTime(t) : fmtDate(t);
443	      ctx.fillText(label, x + 6, axisY + 8);
444	    }
445	  }
446	
447	  function drawSession(
448	    ctx: CanvasRenderingContext2D,
449	    s: AuditSession,
450	    x: number,
451	    y: number,
452	    w: number,
453	    h: number,
454	    pxPerMs: number,
455	  ) {
456	    const isSel = s.id === selectedId;
457	    const isHov = s.id === hoverId;
458	
459	    // Block fill
460	    const grad = ctx.createLinearGradient(0, y, 0, y + h);
461	    grad.addColorStop(0, 'rgba(168, 85, 247, 0.28)');
462	    grad.addColorStop(1, 'rgba(236, 72, 153, 0.12)');
463	    ctx.fillStyle = isSel
464	      ? 'rgba(236, 72, 153, 0.32)'
465	      : isHov
466	        ? 'rgba(168, 85, 247, 0.32)'
467	        : (grad as unknown as string);
468	    // Re-assigning grad through the string branch above is weird in TS -
469	    // just set it directly in the else path:
470	    if (!isSel && !isHov) ctx.fillStyle = grad;
471	
472	    roundRect(ctx, x, y, w, h, 4);
473	    ctx.fill();
474	
475	    // Block stroke
476	    ctx.strokeStyle = isSel
477	      ? 'rgba(236, 72, 153, 0.9)'
478	      : isHov
479	        ? 'rgba(236, 72, 153, 0.55)'
480	        : 'rgba(168, 85, 247, 0.45)';
481	    ctx.lineWidth = isSel ? 2 : 1;
482	    roundRect(ctx, x, y, w, h, 4);
483	    ctx.stroke();
484	
485	    // Event bars are gated by the *viewport* zoom level, not by this
486	    // individual block's width - so all sessions reveal their detail
487	    // together rather than long sessions popping in before short ones.
488	    // See detailOpacity computation in draw().
489	    if (detailOpacity > 0) {
490	      drawEventMarkers(ctx, s, x, y, w, h, pxPerMs, detailOpacity);
491	    }
492	
493	    // Title overlay - appears once the block can hold readable text.
494	    if (w >= 40) {
495	      drawSessionLabel(ctx, s, x, y, w, h);
496	    }
497	
498	    // Cursor overlay - only on the selected session, shows the slice
499	    // currently visible in the detail panel's scroll viewport.
500	    if (isSel && viewportEndT > viewportStartT) {
501	      drawViewportCursor(ctx, x, y, w, h, pxPerMs);
502	    }
503	  }
504	
505	  function drawViewportCursor(
506	    ctx: CanvasRenderingContext2D,
507	    x: number,
508	    y: number,
509	    w: number,
510	    h: number,
511	    pxPerMs: number,
512	  ) {
513	    // Clamp the cursor's pixel range to the session block so it can't
514	    // paint over adjacent blocks on the timeline.
515	    const cx0 = Math.max(x, x + viewportStartT * pxPerMs);
516	    const cx1 = Math.min(x + w, x + viewportEndT * pxPerMs);
517	    const cw = Math.max(3, cx1 - cx0);
518	
519	    ctx.save();
520	    // Tinted rectangle over the visible window.
521	    ctx.fillStyle = 'rgba(236, 72, 153, 0.18)';
522	    ctx.fillRect(cx0, y, cw, h);
523	
524	    // Frame lines at each edge, plus top / bottom rules for emphasis.
525	    ctx.strokeStyle = 'rgba(236, 72, 153, 0.95)';
526	    ctx.lineWidth = 2;
527	    ctx.beginPath();
528	    // Left edge
529	    ctx.moveTo(cx0, y);
530	    ctx.lineTo(cx0, y + h);
531	    // Right edge
532	    ctx.moveTo(cx1, y);
533	    ctx.lineTo(cx1, y + h);
534	    // Top + bottom bars
535	    ctx.moveTo(cx0, y + 1);
536	    ctx.lineTo(cx1, y + 1);
537	    ctx.moveTo(cx0, y + h - 1);
538	    ctx.lineTo(cx1, y + h - 1);
539	    ctx.stroke();
540	
541	    // Small "eye" marker above the block so the cursor is obvious even
542	    // when the block is narrow.
543	    const notchY = y - 6;
544	    const notchX = (cx0 + cx1) / 2;
545	    ctx.fillStyle = 'rgba(236, 72, 153, 0.95)';
546	    ctx.beginPath();
547	    ctx.moveTo(notchX, notchY + 6);
548	    ctx.lineTo(notchX - 5, notchY);
549	    ctx.lineTo(notchX + 5, notchY);
550	    ctx.closePath();
551	    ctx.fill();
552	
553	    ctx.restore();
554	  }
555	
556	  function drawEventMarkers(
557	    ctx: CanvasRenderingContext2D,
558	    s: AuditSession,
559	    x: number,
560	    y: number,
561	    w: number,
562	    h: number,
563	    pxPerMs: number,
564	    opacity: number,
565	  ) {
566	    // Clip to block interior so bars don't leak out at the edges.
567	    ctx.save();
568	    ctx.globalAlpha = opacity;
569	    ctx.beginPath();
570	    roundRect(ctx, x, y, w, h, 4);
571	    ctx.clip();
572	
573	    // Layout: the bottom ~55% of the block is the Gantt strip, split
574	    // into four equal tracks. The top portion of the block is reserved
575	    // for the session caption. If the block is too short overall, the
576	    // strip shrinks but tracks stay proportional.
577	    const stripTop = y + h * 0.45;
578	    const stripH = h - (stripTop - y) - 4; // 4px bottom pad
579	    const trackH = stripH / TRACK_ORDER.length;
580	    const gap = Math.max(1, Math.min(2, trackH * 0.08));
581	    const barH = trackH - gap * 2;
582	
583	    // Draw faint track backgrounds so empty tracks still read as a row.
584	    ctx.fillStyle = 'rgba(255, 255, 255, 0.03)';
585	    for (let i = 0; i < TRACK_ORDER.length; i++) {
586	      const ty = stripTop + i * trackH + gap;
587	      ctx.fillRect(x + 1, ty, w - 2, barH);
588	    }
589	
590	    // Draw each track's events as duration bars.
591	    for (let i = 0; i < TRACK_ORDER.length; i++) {
592	      const kind = TRACK_ORDER[i];
593	      const style = TRACK_STYLE[kind];
594	      const ty = stripTop + i * trackH + gap;
595	      ctx.fillStyle = style.fill;
596	      ctx.strokeStyle = style.stroke;
597	      ctx.lineWidth = 1;
598	
599	      for (const e of s.events) {
600	        if (e.kind !== kind) continue;
601	        // Event ends at e.t; activity started at (e.t - e.dur).
602	        const endX = x + e.t * pxPerMs;
603	        const startX = x + (e.t - e.dur) * pxPerMs;
604	        if (endX < x - 1 || startX > x + w + 1) continue;
605	        const bx = Math.max(startX, x);
606	        const bw = Math.max(1.5, Math.min(endX, x + w) - bx);
607	        ctx.fillRect(bx, ty, bw, barH);
608	        if (bw >= 3) {
609	          // Outline once the bar is wide enough that the stroke doesn't
610	          // just double the perceived thickness.
611	          ctx.strokeRect(bx + 0.5, ty + 0.5, bw - 1, barH - 1);
612	        }
613	      }
614	    }
615	
616	    // Subtle track dividers for legibility.
617	    ctx.strokeStyle = 'rgba(0, 0, 0, 0.25)';
618	    ctx.lineWidth = 1;
619	    for (let i = 1; i < TRACK_ORDER.length; i++) {
620	      const ly = stripTop + i * trackH;
621	      ctx.beginPath();
622	      ctx.moveTo(x + 1, ly);
623	      ctx.lineTo(x + w - 1, ly);
624	      ctx.stroke();
625	    }
626	
627	    // Track labels on the left edge once the block is wide enough.
628	    // These fade with the same opacity so they appear in sync.
629	    if (w >= 260) {
630	      ctx.fillStyle = 'rgba(242, 242, 248, 0.4)';
631	      ctx.font = '10px "JetBrains Mono", ui-monospace, monospace';
632	      ctx.textBaseline = 'middle';
633	      ctx.textAlign = 'left';
634	      for (let i = 0; i < TRACK_ORDER.length; i++) {
635	        const kind = TRACK_ORDER[i];
636	        const cy = stripTop + i * trackH + trackH / 2;
637	        ctx.fillText(TRACK_STYLE[kind].label, x + 8, cy);
638	      }
639	    }
640	
641	    ctx.restore();
642	  }
643	
644	  function drawSessionLabel(
645	    ctx: CanvasRenderingContext2D,
646	    s: AuditSession,
647	    x: number,
648	    y: number,
649	    w: number,
650	    h: number,
651	  ) {
652	    // Short caption when narrow; full title when wide.
653	    ctx.save();
654	    ctx.beginPath();
655	    roundRect(ctx, x + 4, y + 4, w - 8, h - 8, 3);
656	    ctx.clip();
657	
658	    const date = new Date(s.startMs);
659	    const dateStr = date.toLocaleDateString('en-GB', {
660	      month: 'short',
661	      day: 'numeric',
662	    });
663	
664	    ctx.fillStyle = 'rgba(242, 242, 248, 0.95)';
665	    ctx.textBaseline = 'top';
666	    ctx.textAlign = 'left';
667	
668	    if (w < 120) {
669	      // Just the date, vertically centered.
670	      ctx.font = '600 14px "JetBrains Mono", ui-monospace, monospace';
671	      ctx.fillText(dateStr, x + 8, y + 8);
672	    } else {
673	      // Date + duration on first line, then title.
674	      ctx.font = '600 13px "JetBrains Mono", ui-monospace, monospace';
675	      ctx.fillStyle = 'rgba(242, 242, 248, 0.55)';
676	      ctx.fillText(
677	        `${dateStr}  ·  ${fmtDuration(s.durationMs)}  ·  ${
678	          s.stats.user
679	        }U / ${s.stats.assistant}A / ${s.stats.tools}T`,
680	        x + 10,
681	        y + 10,
682	      );
683	      ctx.fillStyle = 'rgba(242, 242, 248, 0.98)';
684	      ctx.font = '600 18px Inter, system-ui, sans-serif';
685	      ctx.fillText(s.title, x + 10, y + 32);
686	    }
687	
688	    ctx.restore();
689	  }
690	
691	  function roundRect(
692	    ctx: CanvasRenderingContext2D,
693	    x: number,
694	    y: number,
695	    w: number,
696	    h: number,
697	    r: number,
698	  ) {
699	    const rr = Math.min(r, w / 2, h / 2);
700	    ctx.beginPath();
701	    ctx.moveTo(x + rr, y);
702	    ctx.lineTo(x + w - rr, y);
703	    ctx.quadraticCurveTo(x + w, y, x + w, y + rr);
704	    ctx.lineTo(x + w, y + h - rr);
705	    ctx.quadraticCurveTo(x + w, y + h, x + w - rr, y + h);
706	    ctx.lineTo(x + rr, y + h);
707	    ctx.quadraticCurveTo(x, y + h, x, y + h - rr);
708	    ctx.lineTo(x, y + rr);
709	    ctx.quadraticCurveTo(x, y, x + rr, y);
710	    ctx.closePath();
711	  }
712	
713	  // Redraw when viewport or selection changes.
714	  $effect(() => {
715	    // Touch reactive deps so Svelte re-runs this when they change.
716	    tMin;
717	    tMax;
718	    hoverId;
719	    selectedId;
720	    canvasW;
721	    canvasH;
722	    viewportStartT;
723	    viewportEndT;
724	    draw();
725	  });
726	
727	  // === Detail panel ==================================================
728	  //
729	  // While a session is open, we also track which slice of its event
730	  // timeline is currently visible in the detail scroll view. That slice
731	  // feeds a "cursor" overlay on the main timeline so the audience can
732	  // see where in the session they are as they scroll the log.
733	
734	  let detailEl: HTMLDivElement | null = $state(null);
735	  let viewportStartT = $state(0);
736	  let viewportEndT = $state(0);
737	  // Indices of the first and last fully-visible event rows - used both
738	  // by the timeline cursor (via their t / dur) and by a subtle highlight
739	  // in the detail panel itself, so it's obvious which rows are feeding
740	  // the cursor's in / out markers.
741	  let viewportFirstIdx = $state(-1);
742	  let viewportLastIdx = $state(-1);
743	
744	  function updateDetailViewport() {
745	    if (!selectedSession || !detailEl) return;
746	    const events = selectedSession.events;
747	    const rows = detailEl.querySelectorAll<HTMLDivElement>(':scope > .ev');
748	    if (rows.length === 0) {
749	      viewportStartT = 0;
750	      viewportEndT = selectedSession.durationMs;
751	      viewportFirstIdx = -1;
752	      viewportLastIdx = -1;
753	      return;
754	    }
755	
756	    // Use getBoundingClientRect() on both the container and each row so
757	    // the comparison happens in screen-coord space. This sidesteps the
758	    // offsetParent / offsetTop confusion that arises because the whole
759	    // segment sits inside a CSS transform (the camera), which breaks the
760	    // assumption that offsetTop is measured from the scroll container.
761	    const containerRect = detailEl.getBoundingClientRect();
762	    const vTop = containerRect.top;
763	    const vBot = containerRect.bottom;
764	
765	    let firstFullyVisible = -1;
766	    let lastFullyVisible = -1;
767	    const EPS = 0.5;
768	    for (let i = 0; i < rows.length; i++) {
769	      const r = rows[i].getBoundingClientRect();
770	      if (r.top + EPS >= vTop && r.bottom - EPS <= vBot) {
771	        if (firstFullyVisible === -1) firstFullyVisible = i;
772	        lastFullyVisible = i;
773	      }
774	    }
775	
776	    // Fallback when no row is fully visible (single row taller than
777	    // the panel): use the first and last rows that overlap the viewport.
778	    if (firstFullyVisible === -1) {
779	      for (let i = 0; i < rows.length; i++) {
780	        const r = rows[i].getBoundingClientRect();
781	        if (r.bottom > vTop) {
782	          firstFullyVisible = i;
783	          break;
784	        }
785	      }
786	      for (let i = rows.length - 1; i >= Math.max(0, firstFullyVisible); i--) {
787	        const r = rows[i].getBoundingClientRect();
788	        if (r.top < vBot) {
789	          lastFullyVisible = i;
790	          break;
791	        }
792	      }
793	    }
794	
795	    const first = events[firstFullyVisible];
796	    const last = events[lastFullyVisible];
797	    if (!first || !last) {
798	      viewportStartT = 0;
799	      viewportEndT = selectedSession.durationMs;
800	      viewportFirstIdx = -1;
801	      viewportLastIdx = -1;
802	      return;
803	    }
804	    viewportStartT = Math.max(0, first.t - first.dur);
805	    viewportEndT = last.t;
806	    viewportFirstIdx = firstFullyVisible;
807	    viewportLastIdx = lastFullyVisible;
808	  }
809	
810	  // Recompute the viewport whenever the selection changes (after the
811	  // detail panel has actually mounted / its new content is laid out).
812	  $effect(() => {
813	    selectedId;
814	    tick().then(() => {
815	      // Reset scroll to top for each new selection so the cursor starts
816	      // at the beginning of the session.
817	      if (detailEl) detailEl.scrollTop = 0;
818	      updateDetailViewport();
819	    });
820	  });
821	
822	  function fmtEventTime(session: AuditSession, e: AuditEvent): string {
823	    const d = new Date(session.startMs + e.t);
824	    return d.toLocaleTimeString('en-GB', {
825	      hour: '2-digit',
826	      minute: '2-digit',
827	      second: '2-digit',
828	    });
829	  }
830	
831	  function closeDetail() {
832	    selectedId = null;
833	  }
834	
835	  // Hovered session metadata (for tooltip)
836	  const hoveredSession = $derived(
837	    hoverId ? AUDIT_DATA.sessions.find((s) => s.id === hoverId) ?? null : null,
838	  );
839	</script>
